        BasicBlock *IBB = PH->getIncomingBlock(I);
        Value *Inc;
        // If the incoming value is from a block that we are about to sink
        // into, then we need to get the value from the new block.
        if (isBlockSunk(IBB)) {
          // ...
        } else {
          // The incoming value is not from a block that we are sinking into.
          // We can just get the value from the original block.
          Builder.SetInsertPoint(IBB->getTerminator());
          Inc = getVectorValue(TE, I);
        }
        NewPhi->addIncoming(Inc, IBB);
      }
```
