```cpp
// around 18950
Value *BoUpSLP::buildVector(const ValueList &VL, unsigned EdgeIdx) {
  // ...
  // If we have a single value, we need to broadcast it.
  if (all_equal(VL)) {
    Value *V = getOperand(VL[0], EdgeIdx);
    // ...
    return Builder.CreateVectorSplat(VL.size(), V);
  }

  // ...
  // Build a vector from the scalar values.
  Value *Vec = PoisonValue::get(VectorType::get(ScalarTy, VL.size(), false));
  for (unsigned i = 0, e = VL.size(); i != e; ++i) {
    Value *V = getOperand(VL[i], EdgeIdx);
    // ...
    Vec = Builder.CreateInsertElement(Vec, V, i);
  }
  return Vec;
}
```
`getOperand` is called for each scalar.
```cpp
// around 18890
Value *BoUpSLP::getOperand(Value *V, unsigned EdgeIdx) {
  if (isa<Constant>(V) || isa<Argument>(V) || isa<GlobalValue>(V))
    return V;

  if (Instruction *I = dyn_cast<Instruction>(V)) {
    auto It = ScalarToTreeEntry.find(I);
    if (It != ScalarToTreeEntry.end()) {
      TreeEntry *TE = It->second;
      // ...
      return getVectorValue(TE, EdgeIdx);
    }
  }
  // ...
  return V;
}
```
